echo "Reading lines one by one with error handling:"
python3 -c "
try:
    with open('/app/categorizationapp/categorizationapp/BankScripts/HDFC.py', 'r', encoding='utf-8') as f:
        lines = [next(f) for _ in range(100)]  # Read first 100 lines
        # Now read lines 100-110 (indices 99-109)
        for i in range(99, 110):
            if i < len(lines):
                print(f'Line {i+1}: {lines[i].rstrip()}')
            else:
                print(f'Line {i+1}: (unexpected end of file)')
except StopIteration:
    print('Reached end of file unexpectedly')
except Exception as e:
    print(f'Error: {e}')
"
